// ServerInterface represents all server handlers.
type ServerInterface interface {
	// Revoke all of the user's sessions.
	// (POST /account/logout-all)
	LogoutAll(w http.ResponseWriter, r *http.Request)
	// Preview an invitation by its token (org name, role, inviter). Usable pre-login via the token capability, so the accept page can render before sign-in.
	// (GET /invitations/{token})
	GetInvitationPreview(w http.ResponseWriter, r *http.Request, token Token)
	// Accept an invitation. Requires a signed-in session whose verified email matches the invited email; creates the membership and occupies the seat.
	// (POST /invitations/{token}/accept)
	AcceptInvitation(w http.ResponseWriter, r *http.Request, token Token)
	// The signed-in user and the orgs they belong to.
	// (GET /me)
	GetMe(w http.ResponseWriter, r *http.Request)
	// Update the signed-in user's profile (name, locale, timezone).
	// (PATCH /me)
	UpdateMe(w http.ResponseWriter, r *http.Request)
	// The social identities linked to the signed-in user.
	// (GET /me/identities)
	ListMyIdentities(w http.ResponseWriter, r *http.Request)
	// Unlink a social identity from the signed-in user.
	// (DELETE /me/identities/{provider})
	UnlinkMyIdentity(w http.ResponseWriter, r *http.Request, provider Provider)
	// The orgs the signed-in user belongs to.
	// (GET /orgs)
	ListOrgs(w http.ResponseWriter, r *http.Request)
	// Create a new org with the caller as owner.
	// (POST /orgs)
	CreateOrg(w http.ResponseWriter, r *http.Request)
	// One org the caller is a member of.
	// (GET /orgs/{orgId})
	GetOrg(w http.ResponseWriter, r *http.Request, orgId OrgId)
	// The org's API keys (metadata only; the secret is never returned).
	// (GET /orgs/{orgId}/api-keys)
	ListAPIKeys(w http.ResponseWriter, r *http.Request, orgId OrgId)
	// Create an API key. The full secret (pulse_sk_...) is returned exactly once in this response and never again. Role is member or admin only.
	// (POST /orgs/{orgId}/api-keys)
	CreateAPIKey(w http.ResponseWriter, r *http.Request, orgId OrgId)
	// Revoke an API key. The key fails auth immediately after.
	// (DELETE /orgs/{orgId}/api-keys/{id})
	RevokeAPIKey(w http.ResponseWriter, r *http.Request, orgId OrgId, id Id)
	// The channel-type catalog: every notification channel type, its config-field schema, and whether the org's plan includes it. Drives the channel picker and config forms with no hardcoding (RFC-007a, PRD-006 section 3).
	// (GET /orgs/{orgId}/channel-types)
	GetChannelTypes(w http.ResponseWriter, r *http.Request, orgId OrgId)

	// (GET /orgs/{orgId}/channels)
	ListChannels(w http.ResponseWriter, r *http.Request, orgId OrgId)

	// (POST /orgs/{orgId}/channels)
	CreateChannel(w http.ResponseWriter, r *http.Request, orgId OrgId)

	// (DELETE /orgs/{orgId}/channels/{id})
	DeleteChannel(w http.ResponseWriter, r *http.Request, orgId OrgId, id Id)

	// (PUT /orgs/{orgId}/channels/{id})
	UpdateChannel(w http.ResponseWriter, r *http.Request, orgId OrgId, id Id)

	// (POST /orgs/{orgId}/channels/{id}/test)
	TestChannel(w http.ResponseWriter, r *http.Request, orgId OrgId, id Id)
	// The active org's plan, usage, and caps (owner/admin).
	// (GET /orgs/{orgId}/entitlements)
	GetEntitlements(w http.ResponseWriter, r *http.Request, orgId OrgId)
	// The org's incidents across all monitors, newest first (PRD-002 4). status filters to currently open incidents; the default returns all.
	// (GET /orgs/{orgId}/incidents)
	ListIncidents(w http.ResponseWriter, r *http.Request, orgId OrgId, params ListIncidentsParams)
	// One incident with its annotation timeline (PRD-002 4). Any member may view.
	// (GET /orgs/{orgId}/incidents/{id})
	GetIncident(w http.ResponseWriter, r *http.Request, orgId OrgId, id Id)
	// Add a note to the incident timeline (PRD-002 4). Member+ may annotate.
	// (POST /orgs/{orgId}/incidents/{id}/annotations)
	AddIncidentAnnotation(w http.ResponseWriter, r *http.Request, orgId OrgId, id Id)
	// Manually close an open incident as an operator override (PRD-002 4). Owner or admin only. Sets a distinct manual close_reason and emits no recovery notification. An already-closed incident is a 409.
	// (POST /orgs/{orgId}/incidents/{id}/close)
	CloseIncident(w http.ResponseWriter, r *http.Request, orgId OrgId, id Id)
	// The pending invitations for the org.
	// (GET /orgs/{orgId}/invitations)
	ListInvitations(w http.ResponseWriter, r *http.Request, orgId OrgId)
	// Invite a teammate by email with a target role.
	// (POST /orgs/{orgId}/invitations)
	CreateInvitation(w http.ResponseWriter, r *http.Request, orgId OrgId)
	// Revoke a pending invitation, freeing its reserved seat.
	// (DELETE /orgs/{orgId}/invitations/{id})
	RevokeInvitation(w http.ResponseWriter, r *http.Request, orgId OrgId, id Id)
	// Resend a pending invitation with a fresh token and 7-day expiry.
	// (POST /orgs/{orgId}/invitations/{id}/resend)
	ResendInvitation(w http.ResponseWriter, r *http.Request, orgId OrgId, id Id)
	// The members of the org with their role and user info.
	// (GET /orgs/{orgId}/members)
	ListMembers(w http.ResponseWriter, r *http.Request, orgId OrgId)
	// Leave the org. The last owner must transfer ownership first.
	// (DELETE /orgs/{orgId}/members/me)
	LeaveOrg(w http.ResponseWriter, r *http.Request, orgId OrgId)
	// Remove a member from the org.
	// (DELETE /orgs/{orgId}/members/{userId})
	RemoveMember(w http.ResponseWriter, r *http.Request, orgId OrgId, userId UserId)
	// Change a member's role.
	// (PATCH /orgs/{orgId}/members/{userId})
	ChangeMemberRole(w http.ResponseWriter, r *http.Request, orgId OrgId, userId UserId)
	// The live per-region check state for the org's monitors (RFC-004 §9): each monitor maps to its regions' current state (scheduled/running/done/failed) with the last outcome. The frontend polls this to render a chip per region. Pass monitor_id to fetch one monitor. Monitors with no live state are omitted.
	// (GET /orgs/{orgId}/monitor-region-states)
	GetMonitorRegionStates(w http.ResponseWriter, r *http.Request, orgId OrgId, params GetMonitorRegionStatesParams)

	// (GET /orgs/{orgId}/monitors)
	ListMonitors(w http.ResponseWriter, r *http.Request, orgId OrgId)

	// (POST /orgs/{orgId}/monitors)
	CreateMonitor(w http.ResponseWriter, r *http.Request, orgId OrgId)

	// (DELETE /orgs/{orgId}/monitors/{id})
	DeleteMonitor(w http.ResponseWriter, r *http.Request, orgId OrgId, id Id)

	// (GET /orgs/{orgId}/monitors/{id})
	GetMonitor(w http.ResponseWriter, r *http.Request, orgId OrgId, id Id)

	// (PUT /orgs/{orgId}/monitors/{id})
	UpdateMonitor(w http.ResponseWriter, r *http.Request, orgId OrgId, id Id)
	// Trigger a check now. It enqueues one probe per region (like a scheduled check) and returns 202 immediately; the per-region progress shows up in the monitor's live region states (poll getMonitorRegionStates). 409 if a check is already running, the monitor is disabled, or you are within the per-monitor cooldown; 429 if you are over the sustained manual-check budget.
	// (POST /orgs/{orgId}/monitors/{id}/check)
	CheckNow(w http.ResponseWriter, r *http.Request, orgId OrgId, id Id)

	// (GET /orgs/{orgId}/monitors/{id}/incidents)
	ListMonitorIncidents(w http.ResponseWriter, r *http.Request, orgId OrgId, id Id, params ListMonitorIncidentsParams)
	// The captured response from the monitor's most recent failed check (PRD-002 3.8).
	// (GET /orgs/{orgId}/monitors/{id}/last-failure)
	GetLastFailure(w http.ResponseWriter, r *http.Request, orgId OrgId, id Id)

	// (GET /orgs/{orgId}/monitors/{id}/results)
	ListResults(w http.ResponseWriter, r *http.Request, orgId OrgId, id Id, params ListResultsParams)

	// (GET /orgs/{orgId}/status-pages)
	ListStatusPages(w http.ResponseWriter, r *http.Request, orgId OrgId)
	// Create a status page (member+; PRD-004 10).
	// (POST /orgs/{orgId}/status-pages)
	CreateStatusPage(w http.ResponseWriter, r *http.Request, orgId OrgId)

	// (DELETE /orgs/{orgId}/status-pages/{id})
	DeleteStatusPage(w http.ResponseWriter, r *http.Request, orgId OrgId, id Id)

	// (GET /orgs/{orgId}/status-pages/{id})
	GetStatusPage(w http.ResponseWriter, r *http.Request, orgId OrgId, id Id)
	// Update a status page and its displayed monitors (member+).
	// (PUT /orgs/{orgId}/status-pages/{id})
	UpdateStatusPage(w http.ResponseWriter, r *http.Request, orgId OrgId, id Id)
	// Publish or unpublish a status page (member+; PRD-004 6). Publishing makes the public URL resolve; unpublishing returns it to draft and stops resolving.
	// (PUT /orgs/{orgId}/status-pages/{id}/publish)
	PublishStatusPage(w http.ResponseWriter, r *http.Request, orgId OrgId, id Id)
	// Hand ownership to another member (owner only). The new owner must already be a member. The acting owner may step down to admin or stay an owner.
	// (POST /orgs/{orgId}/transfer-ownership)
	TransferOwnership(w http.ResponseWriter, r *http.Request, orgId OrgId)
	// The org's outbound webhooks (the signing secret is never returned).
	// (GET /orgs/{orgId}/webhooks)
	ListWebhooks(w http.ResponseWriter, r *http.Request, orgId OrgId)
	// Register an outbound webhook. The signing secret is returned exactly once in this response and never again. url must be https.
	// (POST /orgs/{orgId}/webhooks)
	CreateWebhook(w http.ResponseWriter, r *http.Request, orgId OrgId)
	// Delete an outbound webhook. Pulse Pager stops delivering to it immediately.
	// (DELETE /orgs/{orgId}/webhooks/{id})
	DeleteWebhook(w http.ResponseWriter, r *http.Request, orgId OrgId, id Id)
	// One outbound webhook (the signing secret is redacted).
	// (GET /orgs/{orgId}/webhooks/{id})
	GetWebhook(w http.ResponseWriter, r *http.Request, orgId OrgId, id Id)
	// Update an outbound webhook's url, enabled flag, and subscribed events.
	// (PUT /orgs/{orgId}/webhooks/{id})
	UpdateWebhook(w http.ResponseWriter, r *http.Request, orgId OrgId, id Id)
	// Rotate the signing secret. The new secret is returned exactly once in this response; the old one stops verifying immediately.
	// (POST /orgs/{orgId}/webhooks/{id}/rotate-secret)
	RotateWebhookSecret(w http.ResponseWriter, r *http.Request, orgId OrgId, id Id)
	// The public plan catalog (tiers and their limits).
	// (GET /plans)
	ListPlans(w http.ResponseWriter, r *http.Request)
	// The public, unauthenticated data endpoint a published status page renders from (PRD-004 3.6, 8). No auth, no org context. Returns only the public-safe projection; a draft or unknown slug is a 404 (PRD-004 6). Read-mostly and cacheable so the page stays up during the customer's own incident (PRD-004 8).
	// (GET /public/status-pages/{slug})
	GetPublicStatusPage(w http.ResponseWriter, r *http.Request, slug string)
}

